const result = [];

items.forEach(item => {
  const clientUrl = item.json["Client blog URL"];
  const competitorUrls = item.json["Competitor blog URL"];

  // Add client URL if it's not empty
  if (clientUrl && clientUrl.trim() !== '') {
    result.push({ url: clientUrl.trim() });
  }

  // Handle competitor URLs
  if (Array.isArray(competitorUrls)) {
    competitorUrls.forEach(url => {
      if (url && url.trim() !== '') {
        result.push({ url: url.trim() });
      }
    });
  } else if (typeof competitorUrls === 'string') {
    // In case it's a newline-separated string
    competitorUrls.split(/\r?\n/).forEach(url => {
      if (url && url.trim() !== '') {
        result.push({ url: url.trim() });
      }
    });
  }
});

return result;

const outputs = [];

function capitaliseKey(k) {
  return k.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
}

function renderObjectAsBullet(obj) {
  const priorityKeys = ['title', 'gap', 'insight', 'step', 'name'];
  let headline = null;

  for (const pk of priorityKeys) {
    if (obj.hasOwnProperty(pk) && obj[pk]) {
      headline = String(obj[pk]);
      break;
    }
  }

  if (!headline) {
    const firstEntry = Object.entries(obj).find(([, v]) => typeof v === 'string' || typeof v === 'number');
    if (firstEntry) headline = String(firstEntry[1]);
    else {
      const k = Object.keys(obj)[0];
      headline = k ? `${capitaliseKey(k)}: ${String(obj[k])}` : JSON.stringify(obj);
    }
  }

  const lines = [`• ${headline}`];

  for (const [k, v] of Object.entries(obj)) {
    if (v === undefined || v === null) continue;
    if (String(v) === headline) continue;

    const vStr = typeof v === 'object' ? JSON.stringify(v) : String(v);
    lines.push(`    - ${capitaliseKey(k)}: ${vStr}`);
  }

  return lines.join('\n');
}

for (const item of items) {
  const data = item.json?.output ?? item.output ?? item.json ?? {};

  if (typeof data === 'object' && data !== null) {
    for (const [sectionTitle, sectionContent] of Object.entries(data)) {
      let formattedContent = "";

      if (Array.isArray(sectionContent)) {
        const lines = sectionContent.map(elem =>
          typeof elem === 'object' && elem !== null
            ? renderObjectAsBullet(elem)
            : `• ${String(elem)}`
        );
        formattedContent = lines.join('\n\n');
      } else if (typeof sectionContent === 'object' && sectionContent !== null) {
        formattedContent = renderObjectAsBullet(sectionContent);
      } else {
        formattedContent = String(sectionContent);
      }

      outputs.push({
        Section: sectionTitle,
        Content: formattedContent
      });
    }
  } else {
    outputs.push({
      Section: "Raw Output",
      Content: String(data)
    });
  }
}

return outputs;

