const result = [];
const seen = new Set();

items.forEach(item => {
  // Handle both wrapped and unwrapped structures
  let content = item.json?.choices?.[0]?.message?.content 
             || item.choices?.[0]?.message?.content;

  if (content) {
    let links;

    try {
      // Try parsing as-is
      links = JSON.parse(content);
    } catch (e) {
      // If parsing fails, handle code-fenced JSON
      const fenced = content.match(/```json\s*([\s\S]*?)\s*```/);
      if (fenced) {
        try {
          links = JSON.parse(fenced[1]);
        } catch (err) {
          links = [];
        }
      } else {
        // Otherwise, try to extract the first JSON array in the string
        const arrayMatch = content.match(/\[[\s\S]*\]/);
        if (arrayMatch) {
          try {
            links = JSON.parse(arrayMatch[0]);
          } catch (err) {
            links = [];
          }
        } else {
          links = [];
        }
      }
    }

    // Add to results if we got an array
    if (Array.isArray(links)) {
      links.forEach(link => {
        const clean = String(link).trim();
        if (clean && !seen.has(clean)) {
          seen.add(clean);
          result.push({ url: clean });
        }
      });
    }
  }
});

return result;

