for (const item of $input.all()) {
  const markdown = item.json.data?.markdown || '';
  const statusCode = item.json.data?.metadata?.statusCode || 0;

  const wordCount = statusCode === 200
    ? markdown.trim().split(/\s+/).length
    : 0;

  // Add word count to item
  item.json.wordCount = wordCount;
}

return $input.all();

const workflowStaticData = $getWorkflowStaticData('global');

for (const item of $input.all()) {
  item.json.documentID = workflowStaticData.documentID
  item.json.timestamp = workflowStaticData.timestamp
}

return $input.all();

const groupedResults = [];

for (const item of $input.all()) {
  const dataString = item.json.data;

  const result = {
    keywords: []
  };

  // If SEMrush returned an error, include empty keywords
  if (dataString.startsWith('ERROR')) {
    groupedResults.push({ json: result });
    continue;
  }

  const lines = dataString.trim().split('\r\n');
  const headers = lines[0].split(';');
  const keywords = [];

  for (let i = 1; i < lines.length; i++) {
    const values = lines[i].split(';');
    const obj = {};

    for (let j = 0; j < headers.length; j++) {
      const header = headers[j].trim();
      const value = values[j]?.trim();
      const num = Number(value);
      obj[header] = isNaN(num) || value === '' ? value : num;
    }

    keywords.push(obj);
  }

  // Sort keywords by ascending position (best rank)
  keywords.sort((a, b) => a['Position'] - b['Position']);

  result.keywords = keywords.slice(0, 5);

  groupedResults.push({ json: result });
}

return groupedResults;

